import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"EG",currency:"EGP",flag:"🇪🇬",nameEn:"Egypt",nameAr:"مصر",fixedPeg:!1,decimals:2,timezone:"Africa/Cairo",relatedCountries:[{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"jordan.html",nameEn:"Jordan",nameAr:"الأردن",flag:"🇯🇴"},{file:"morocco.html",nameEn:"Morocco",nameAr:"المغرب",flag:"🇲🇦"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"india.html",nameEn:"India",nameAr:"الهند",flag:"🇮🇳"}],faqEn:[{q:"What is today's gold price in Egypt?",a:"The Egyptian Pound (EGP) has been a floating currency since 2016, meaning the exchange rate fluctuates and significantly affects local gold prices. The most popular karat in Egypt is 21K (عيار 21). Prices on this page are updated every 90 seconds from the live XAU/USD spot rate and the current EGP exchange rate."},{q:"Why is 21K so popular in Egypt?",a:"Traditional Egyptian jewellery has long been crafted at 21K purity, striking a balance between gold content, durability, and affordability. The 18K karat is gaining popularity for modern European and Italian-style designs, while 24K is reserved for investment bars and coins."},{q:"Where can I buy gold in Egypt?",a:"Khan el-Khalili bazaar in Islamic Cairo is Egypt's most iconic gold market, with goldsmiths whose craft dates back centuries. The Zamalek neighbourhood in Cairo and the gold sections of City Stars Mall are popular modern alternatives. Most major cities have dedicated gold souks."},{q:"How does Egypt's currency affect gold prices?",a:"The Egyptian Pound has depreciated significantly against the US Dollar since its float in 2016. Because gold is priced globally in USD, a weaker EGP means higher local gold prices in nominal terms. During periods of high inflation, Egyptians often increase gold purchases as a hedge and store of value, driving up local demand and premiums."}],faqAr:[{q:"ما هو سعر الذهب اليوم في مصر؟",a:"يعمل الجنيه المصري (EGP) بنظام التعويم الحر منذ عام 2016، مما يعني تذبذب سعر الصرف وتأثيره الكبير على أسعار الذهب المحلية. العيار الأكثر شيوعاً في مصر هو عيار 21. يتم تحديث الأسعار في هذه الصفحة كل 90 ثانية استناداً إلى سعر XAU/USD الفوري وسعر صرف الجنيه المصري الحالي."},{q:"لماذا يحظى عيار 21 بهذه الشعبية الواسعة في مصر؟",a:"اشتُهرت المجوهرات المصرية التقليدية بصنعها من عيار 21، إذ يحقق توازناً مثالياً بين نسبة الذهب والمتانة والسعر المعقول. يكتسب عيار 18 شعبيةً متزايدة للتصاميم الأوروبية والإيطالية الحديثة، بينما يُخصص عيار 24 للسبائك والعملات الاستثمارية."},{q:"أين يمكنني شراء الذهب في مصر؟",a:"يُعدّ خان الخليلي في القاهرة الإسلامية أشهر أسواق الذهب في مصر، حيث يمتد تاريخ الصاغة فيه لقرون. يُعدّ حي الزمالك في القاهرة وأقسام الذهب في سيتي ستارز مول من البدائل الحديثة المميزة. وتضم معظم المدن الكبرى أسواقاً مخصصةً للذهب."},{q:"كيف يؤثر سعر صرف الجنيه المصري على أسعار الذهب؟",a:"تراجعت قيمة الجنيه المصري تراجعاً ملحوظاً مقابل الدولار الأمريكي منذ تعويمه عام 2016. ولأن الذهب يُسعَّر عالمياً بالدولار، فإن انخفاض قيمة الجنيه يرفع أسعار الذهب محلياً بالقيمة الاسمية. وفي فترات التضخم المرتفع، يلجأ المصريون كثيراً إلى شراء الذهب كوسيلة للتحوط وحفظ القيمة، مما يرفع الطلب المحلي والأسعار."}]});
